"""Missing tests part 3: AP Arts (5 units) + AP Languages (8 units) + AP Capstone (2 units)"""

def mc(q, a, b, c, d, correct, exp):
    return {"type":"mc","q":q,"choices":[a,b,c,d],"correct":correct,"exp":exp}

